import { IMessageComposer } from '@nitrots/nitro-renderer';

export class GangInviteComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(username: string) {
        this._data = [username];
        console.log('[📤] GangInviteComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
